const itemsIn = $input.all();
if (!itemsIn.length) throw new Error('No RSS items were returned from the feed.');

const stripHtml = (text) => String(text || '')
  .replace(/<[^>]*>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

const normalized = itemsIn.map((item, index) => {
  const j = item.json || {};
  const enclosure = j.enclosure || {};
  const rawSummary = j.contentSnippet || j.content || j.description || '';
  const latestGuid = String(j.guid || j.id || '').trim();
  const latestLink = String(j.link || j.url || '').trim();
  const cleanSummary = stripHtml(rawSummary);
  const shortSummary = cleanSummary.length > 600 ? cleanSummary.slice(0, 597) + '...' : cleanSummary;
  return {
    latestTitle: String(j.title || '').trim(),
    latestLink,
    latestGuid,
    latestPubDate: j.pubDate || j.isoDate || '',
    latestCreator: j.creator || j['dc:creator'] || '',
    imageUrl: enclosure.url || '',
    imageType: enclosure.type || '',
    previewSummary: shortSummary,
    dedupeKey: latestGuid || latestLink,
    rssIndex: index
  };
}).filter(item => item.latestTitle && item.latestLink && item.dedupeKey);

normalized.sort((a, b) => new Date(b.latestPubDate || 0) - new Date(a.latestPubDate || 0));
if (!normalized.length) throw new Error('RSS feed items are missing title, link, or dedupe key after normalization.');

const testMode = true; // CHANGE ONLY THIS: true = preview only, false = allow real post path
const aiMode = 'auto'; // CHANGE ONLY THIS: 'auto' = Groq then Ollama fallback; 'groq' = Groq then Ollama fallback; 'ollama' = Ollama only
const postAsOrg = false; // CHANGE ONLY THIS: true = company page, false = personal account
const imageGenEnabled = false; // CHANGE ONLY THIS: true = Cloudflare branded image, false = existing RSS image only
const linkedInPersonUrn = 'ILdXt_7ylP'; // CHANGE THIS ONCE: your personal LinkedIn URN
const linkedInOrgUrn = '108001978'; // CHANGE THIS ONCE: your LinkedIn company page ID
const authorUrn = postAsOrg
  ? `urn:li:organization:${linkedInOrgUrn}`
  : `urn:li:person:${linkedInPersonUrn}`;
const postNow = !testMode;

return [{ json: {
  allItems: normalized,
  rssItemCount: normalized.length,
  testMode,
  postNow,
  imageGenEnabled,
  linkedInPersonUrn,
  linkedInOrgUrn,
  postAsOrg,
  authorUrn,
  status: testMode ? 'LIVE_TEST_READY' : 'LIVE_POST_READY',
  workflowPhase: testMode ? 'PREVIEW_ONLY' : 'READY_TO_POST',
  sourceFeed: 'https://www.patchifi.com/blog-feed.xml',
  companyName: 'Patchifi',
  profileName: 'Patchifi',
  previewProfileLabel: testMode ? 'Preview mode' : 'Posting mode',
  aiMode,
  groqModel: 'llama-3.3-70b-versatile',
  ollamaModel: 'qwen2.5:7b',
  generatedAt: '',
  aiProvider: aiMode === 'ollama' ? 'ollama' : 'groq',
  approvalStatus: testMode ? 'preview_only' : 'post_allowed',
  nextAction: testMode
    ? 'Preview mode is ON. The workflow will scan the RSS feed newest-first, pick the first item not yet in the dedupe log, and stop at the browser preview. Switch testMode to false when you want the post path.'
    : 'Posting mode is ON. The workflow will scan newest-first, pick the first unposted item, and then continue to LinkedIn posting.'
}}];

const source = $items("Normalize Dedupe Lookup", 0, 0)[0].json;
let parseStatus = 'success';
const llmItem = $input.first().json || {};

const normalizeWhitespace = (text) => String(text || '').replace(/\r\n/g, '\n').replace(/[ \t]+\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim();
const normalizeHashtags = (value) => {
  if (Array.isArray(value)) return value.map(v => String(v || '').trim()).filter(Boolean).map(v => v.startsWith('#') ? v : `#${v.replace(/^#+/, '')}`);
  if (typeof value === 'string') return value.split(/[,\s]+/).map(v => v.trim()).filter(Boolean).map(v => v.replace(/^['\"]|['\"]$/g, '')).map(v => v.startsWith('#') ? v : `#${v.replace(/^#+/, '')}`);
  return [];
};
const countWords = (text) => String(text || '').trim().split(/\s+/).filter(Boolean).length;
const extractParsed = (payload) => {
  if (!payload || typeof payload !== 'object') return null;
  if (payload.hook || payload.body || payload.caption) return payload;
  if (payload.output && typeof payload.output === 'object') return payload.output;
  if (payload.json && typeof payload.json === 'object' && (payload.json.hook || payload.json.body || payload.json.caption)) return payload.json;
  return null;
};
const fallbackParseRaw = (raw) => {
  let text = String(raw || '').trim();
  if (!text) return null;
  text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  try { return JSON.parse(text); } catch (e1) {}
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    const clipped = text.slice(start, end + 1);
    try { return JSON.parse(clipped); } catch (e2) {}
    try {
      const fixed = clipped
        .replace(/([{,]\s*)([A-Za-z_][A-Za-z0-9_]*)(\s*:)/g, '$1"$2"$3')
        .replace(/,\s*}/g, '}')
        .replace(/,\s*]/g, ']');
      return JSON.parse(fixed);
    } catch (e3) {}
  }
  return null;
};

let parsed = extractParsed(llmItem);
if (!parsed) {
  parsed = fallbackParseRaw(llmItem.output || llmItem.text || llmItem.response || llmItem.completion || llmItem.content || '');
}
if (!parsed && typeof llmItem === 'string') {
  parsed = fallbackParseRaw(llmItem);
}
parsed = parsed || {};

const aiHook = normalizeWhitespace(parsed.hook || '');
const aiBody = normalizeWhitespace(parsed.body || '');
const aiCaption = normalizeWhitespace(parsed.caption || '');
const aiHashtagsArray = normalizeHashtags(parsed.hashtags);
const aiHashtags = aiHashtagsArray.join(' ');
const latestLink = String(source.latestLink || '').trim();
const latestTitle = String(source.latestTitle || '').trim();

const stripHashtagsFromCaption = (text) => String(text || '').replace(/(^|\s)#\w+/g, ' ').replace(/[ \t]+/g, ' ').trim();
const ensureLink = (text) => {
  const value = normalizeWhitespace(text);
  if (!latestLink) return value;
  if (value.includes(latestLink)) return value;
  return value ? `${value}\n\n${latestLink}` : latestLink;
};

let linkedInPostText = '';
if (aiCaption) {
  linkedInPostText = normalizeWhitespace(stripHashtagsFromCaption(aiCaption));
} else if (aiHook || aiBody) {
  linkedInPostText = normalizeWhitespace([aiHook, aiBody].filter(Boolean).join('\n\n'));
} else {
  linkedInPostText = '';
}
if (aiHashtags) linkedInPostText = `${linkedInPostText}\n\n${aiHashtags}`.trim();
linkedInPostText = ensureLink(linkedInPostText);
linkedInPostText = normalizeWhitespace(linkedInPostText);

const qualityWarnings = [];
if (!aiHook) qualityWarnings.push('Missing hook.');
if (!aiBody) qualityWarnings.push('Missing body.');
if (!aiCaption) qualityWarnings.push('Missing caption \u2014 assembled from hook/body fallback.');
if (aiHook && latestTitle && aiHook.toLowerCase() === latestTitle.toLowerCase()) qualityWarnings.push('Hook restates the article title.');

const bannedPhrases = [
  'visit our blog',
  'visit our post',
  'unlock these benefits',
  'discover how',
  'optimize your operations',
  'ensure your systems stay up-to-date',
  'automation tools',
  'without manual intervention',
  'maintaining a secure and operational environment',
  "in today's fast-paced",
  'unprecedented complexity',
  'growing complexity',
  'increased complexity',
  'major challenge',
  'ever-growing',
  'rapidly evolving landscape',
  'critical importance',
  'plays a vital role',
  'is more important than ever',
  'operational discipline',
  'operational rigor',
  'endpoint consistency',
  'coverage consistency',
  'visibility to action',
  'not just a convenience',
  'matters more than',
  'same operational flow',
  'stronger workflow',
  'daunting task',
  'like herding cats'
];
const lowerCaption = String(aiCaption || linkedInPostText || '').toLowerCase();
const lowerHook = String(aiHook || '').toLowerCase();
const allCaptionText = `${aiHook} ${aiBody} ${aiCaption}`;
const questionCount = (allCaptionText.match(/\?/g) || []).length;
if (questionCount > 1) qualityWarnings.push(`Too many questions (${questionCount}; maximum 1).`);
if (questionCount === 1) {
  const questionIndex = aiCaption.indexOf('?');
  const afterQuestion = questionIndex >= 0 ? aiCaption.slice(questionIndex + 1).trim() : '';
  const nextLines = afterQuestion.split(/\n+/).filter(Boolean).slice(0, 2).join(' ').replace(/#[A-Za-z0-9_]+/g, '').replace(/https?:\/\/\S+/g, '').trim();
  const answerSignals = /(start|focus|prioriti[sz]|identify|confirm|verify|review|assess|address|fix|patch|deploy|use|look at|the answer|teams can|it means|this means|that means|first)/i;
  if (!nextLines || nextLines.split(/\s+/).filter(Boolean).length < 5 || !answerSignals.test(nextLines)) qualityWarnings.push('Question is not answered with a practical insight in the next one or two lines.');
}
if (/\b(unprecedented complexity|strategic approach|new reality|without compromising|ai-driven insights|navigate this storm|surge requires)\b/i.test(allCaptionText)) qualityWarnings.push('Contains banned vague setup language.');
if (/^(how|why|what|is|are|can|should)\b[^\n]*\?/i.test(String(aiHook || ''))) qualityWarnings.push('Hook opens as a question; use a declarative insight instead.');
const sourceFactText = `${source.latestTitle || ''} ${source.previewSummary || ''}`.toLowerCase().replace(/\s+/g, '');
const captionWithoutUrl = String(aiCaption || linkedInPostText || '').replace(latestLink, ' ');
const claimedNumericTokens = captionWithoutUrl.match(/(?:[$â‚¬Â£]\s*)?\d+(?:,\d{3})*(?:\.\d+)?(?:%|\+|k|m|b)?/gi) || [];
const unsupportedNumericClaims = claimedNumericTokens.filter(token => {
  const normal = String(token).toLowerCase().replace(/\s+/g, '');
  if (!normal) return false;
  return !sourceFactText.includes(normal);
});
if (unsupportedNumericClaims.length) qualityWarnings.push(`Review numeric claim(s) before publishing: ${unsupportedNumericClaims.join(', ')}.`);
if (/(ensures?|guarantees?|eliminates?|prevents?|keeps? (?:zero[- ]?days?|threats?|exploits?) (?:at bay|away)|stops? (?:all )?(?:attacks?|exploits?))/i.test(`${aiHook} ${aiBody} ${aiCaption}`)) qualityWarnings.push('Possible guaranteed outcome not explicitly supported by the source.');
for (const phrase of bannedPhrases) {
  if (lowerCaption.includes(phrase) || lowerHook.includes(phrase)) {
    qualityWarnings.push(`Contains banned generic phrase: ${phrase}.`);
  }
}

const hookLooksHeadline = Boolean(aiHook) && /^[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){3,}$/.test(aiHook) && aiHook.length < 90 && !/[?!]/.test(aiHook);
if (hookLooksHeadline) qualityWarnings.push('Hook looks like a title-case headline instead of a natural sentence, question, or statement.');

const proseOnly = String(aiCaption || linkedInPostText || '').replace(latestLink, '').replace(/#[A-Za-z0-9_]+/g, '').trim();
const captionWordCount = countWords(proseOnly || aiCaption || linkedInPostText);
if (captionWordCount < 50) qualityWarnings.push(`Caption/post is short (${captionWordCount} words; target 60-130).`);
if (captionWordCount > 160) qualityWarnings.push(`Caption/post is long (${captionWordCount} words; target 60-130).`);
if (aiHashtagsArray.length < 5) qualityWarnings.push(`Only ${aiHashtagsArray.length} hashtags (target 5-9).`);
if (aiHashtagsArray.length > 9) qualityWarnings.push(`Too many hashtags (${aiHashtagsArray.length}; target 5-9).`);
if (latestLink && !linkedInPostText.includes(latestLink)) qualityWarnings.push('Article link missing from final post text.');

const sentenceList = proseOnly
  .split(/(?<=[.!?])\s+/)
  .map(s => s.trim())
  .filter(Boolean);
const longSentences = sentenceList.filter(s => s.split(/\s+/).filter(Boolean).length > 28);
if (longSentences.length) qualityWarnings.push(`Has ${longSentences.length} very long sentence(s) over 28 words.`);

const emojiMatches = (aiCaption.match(/[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}]/gu) || []);
if (emojiMatches.length > 3) qualityWarnings.push(`Too many emojis (${emojiMatches.length}; keep to 0-2).`);

const concreteDetailPatterns = [
  /endpoint/i, /downtime/i, /remediation/i, /patch/i, /vulnerab/i, /support/i,
  /access/i, /backlog/i, /resolution/i, /visibility/i, /\d/, /exploit/i, /breach/i, /compliance/i
];
const hasConcreteDetail = concreteDetailPatterns.some((pattern) => pattern.test(String(aiCaption || linkedInPostText || '')));
if (!hasConcreteDetail) qualityWarnings.push('Missing a concrete operational detail, fact, or number from the article.');

if (!aiHook && !aiBody && !aiCaption) parseStatus = 'failed';
else if (qualityWarnings.length) parseStatus = 'partial';

return [{ json: {
  ...source,
  generatedAt: new Date().toISOString(),
  aiHook,
  aiBody,
  aiHashtags,
  aiHashtagsArray,
  aiCaption,
  linkedInPostText,
  linkedInPostPreview: ['--- LINKEDIN POST PREVIEW ---', linkedInPostText, '--- END PREVIEW ---'].join('\n'),
  parseStatus,
  qualityWarnings,
  wordCount: captionWordCount,
  characterCount: linkedInPostText.length,
  hashtagCount: aiHashtagsArray.length,
  status: parseStatus === 'failed' ? 'LIVE_TEST_FAILED' : 'LIVE_TEST_PREVIEW_READY',
  nextAction: parseStatus === 'failed' ? 'Review AI output and do not post.' : 'Preview is ready. Check linkedInVisualHtml and set postNow to true only when you want to publish.'
}}];

