parameters.jsCode:
const item = $items('Preview Output', 0, 0)[0].json;
return [{ json: {
  dedupeKey: item.dedupeKey,
  latestTitle: item.latestTitle,
  latestLink: item.latestLink,
  processedAt: new Date().toISOString()
}}];

const input = $input.first();
const item = input.json || {};
const inputBinary = input.binary || {};

const escapeHtml = (s) => String(s || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const nl2br = (s) => escapeHtml(String(s || '')).replace(/\n/g, '<br>');
const hashtagsArray = Array.isArray(item.aiHashtagsArray) ? item.aiHashtagsArray.filter(Boolean) : [];
const hashtags = hashtagsArray.length ? hashtagsArray.join(' ') : String(item.aiHashtags || '').trim();
const textWithoutTags = String(item.linkedInPostText || '').replace(/\n\n#[A-Za-z0-9_# ]+$/m, '').trim();
const profileName = String(item.profileName || 'Patchifi');
const profileLabel = String(item.previewProfileLabel || 'Preview mode');
const binaryImage = inputBinary?.data;
const embeddedBinaryUrl = binaryImage?.data ? `data:${binaryImage.mimeType || 'image/png'};base64,${binaryImage.data}` : '';
const imageUrl = String(item.generatedImagePreviewUrl || item.previewImageUrl || embeddedBinaryUrl || item.imageUrl || '').trim();
const latestLink = String(item.latestLink || '').trim();
const latestTitle = String(item.latestTitle || '').trim();
const articleHost = (() => {
  try {
    return new URL(latestLink).hostname.replace(/^www\./, '');
  } catch {
    return 'patchifi.com';
  }
})();

const html = `<!doctype html>
<html>
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>LinkedIn Preview</title>
  <style>
    body { font-family: Arial, Helvetica, sans-serif; background: #f3f2ef; padding: 24px; margin: 0; }
    .shell { max-width: 900px; margin: 0 auto; }
    .note { margin: 0 auto 16px auto; width: 640px; color: #666; font-size: 12px; }
    .card { width: 640px; margin: 0 auto; background: #fff; border: 1px solid #e0dfdc; border-radius: 12px; overflow: hidden; box-shadow: 0 1px 2px rgba(0,0,0,.08); }
    .head { display: flex; gap: 12px; padding: 16px 16px 8px 16px; }
    .avatar { width: 48px; height: 48px; border-radius: 50%; background: #0a66c2; color: #fff; display: flex; align-items: center; justify-content: center; font-weight: 700; font-size: 18px; flex: 0 0 48px; }
    .meta1 { font-weight: 700; color: #191919; font-size: 15px; }
    .meta2 { color: #666; font-size: 13px; margin-top: 2px; }
    .text { padding: 0 16px 12px 16px; color: #191919; font-size: 15px; line-height: 1.5; word-break: break-word; }
    .tags { color: #0a66c2; font-weight: 600; margin-top: 10px; }
    .hero { width: 100%; max-height: 360px; object-fit: cover; border-top: 1px solid #e0dfdc; border-bottom: 1px solid #e0dfdc; display: block; background:#f6f6f6; }
    .linkcard { display: block; text-decoration: none; color: inherit; border-top: 1px solid #e0dfdc; background: #fff; }
    .linkmeta { padding: 12px 16px 16px 16px; }
    .linkhost { color: #666; font-size: 12px; text-transform: uppercase; margin-bottom: 6px; }
    .linktitle { font-size: 16px; font-weight: 700; color: #191919; margin-bottom: 4px; }
    .linkurl { font-size: 13px; color: #666; word-break: break-all; }
    .actions { display: flex; justify-content: space-around; padding: 10px 0; border-top: 1px solid #e0dfdc; color: #666; font-size: 14px; }
    .panel { width: 640px; margin: 16px auto 0 auto; background:#fff; border:1px solid #e0dfdc; border-radius:12px; padding:12px 16px; color:#444; font-size:13px; }
    .panel code { font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; font-size:12px; }
  </style>
</head>
<body>
  <div class="shell">
    <div class="note">This is a browser-rendered preview of the LinkedIn post card.</div>
    <div class="card">
      <div class="head">
        <div class="avatar">${escapeHtml(profileName.charAt(0).toUpperCase() || 'P')}</div>
        <div>
          <div class="meta1">${escapeHtml(profileName)}</div>
          <div class="meta2">${escapeHtml(profileLabel)}</div>
        </div>
      </div>
      <div class="text">
        ${nl2br(textWithoutTags)}
        ${hashtags ? `<div class="tags">${escapeHtml(hashtags)}</div>` : ''}
      </div>
      ${imageUrl ? `<img class="hero" src="${escapeHtml(imageUrl)}" alt="Article image">` : ''}
      <a class="linkcard" href="${escapeHtml(latestLink)}" target="_blank" rel="noopener noreferrer">
        <div class="linkmeta">
          <div class="linkhost">${escapeHtml(articleHost)}</div>
          <div class="linktitle">${escapeHtml(latestTitle)}</div>
          <div class="linkurl">${escapeHtml(latestLink)}</div>
        </div>
      </a>
      <div class="actions"><div>Like</div><div>Comment</div><div>Repost</div><div>Send</div></div>
    </div>
    <div class="panel">
      <div><strong>How to view:</strong> paste <code>previewBrowserUrl</code> into a browser address bar, or save <code>htmlForFile</code> as <code>linkedin-preview.html</code>.</div>
    </div>
  </div>
</body>
</html>`;

const previewBrowserUrl = imageUrl.startsWith('data:image/') ? 'Use htmlForFile or the attached preview image binary; large inline images can exceed browser data-URL limits.' : 'data:text/html;charset=utf-8,' + encodeURIComponent(html);
const previewSummary = [
  `Title: ${latestTitle || '(missing title)'}`,
  `Link: ${latestLink || '(missing link)'}`,
  `Image: ${imageUrl || 'No image found'}`,
  `Has image: ${imageUrl ? 'yes' : 'no'}`,
  `Parse status: ${item.parseStatus || ''}`,
  `Word count: ${Number(item.wordCount || 0)}`,
  `Hashtags: ${hashtags || '(none)'}`,
  `Mode: ${item.testMode ? 'preview only' : 'posting allowed'}`
].join('\n');

return [{
  json: {
    ...item,
    linkedInVisualHtml: html,
    htmlForFile: html,
    previewBrowserUrl,
    linkedInPreviewMode: 'HTML_BROWSER_PREVIEW',
    previewTitle: latestTitle,
    previewLink: latestLink,
    previewImageUrl: imageUrl,
    previewHasImage: Boolean(imageUrl),
    previewHashtags: hashtagsArray,
    previewTextOnly: textWithoutTags,
    previewSummary,
    previewOpenInstructions: imageUrl.startsWith('data:image/') ? 'Save htmlForFile as linkedin-preview.html and open it locally. Download the output binary named previewHtml; it is a complete .html preview file. The generated image remains available as binary data.' : 'Open previewBrowserUrl in a browser for instant visual preview, or save htmlForFile into linkedin-preview.html and open it.',
    previewImageDataUrl: imageUrl
  },
  binary: {
    ...inputBinary,
    previewHtml: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: `linkedin-preview-${String(item.dedupeKey || Date.now()).replace(/[^a-z0-9]/gi, '-').slice(0, 80)}.html`
    }
  }
}];

const input = $input.first();
const item = input.json || {};
const binaries = input.binary || {};
return [{
  json: {
    openPreview: 'Download previewHtml from the Binary tab and open it in your browser for the complete rendered LinkedIn preview.',
    previewBrowserUrl: String(item.previewBrowserUrl || ''),
    previewHtmlDownload: binaries.previewHtml ? 'Available in this nodeâ€™s Binary tab as previewHtml (.html).' : 'Not available â€” run the image preview path first.',
    previewImageDownload: binaries.data ? 'Available in this nodeâ€™s Binary tab as data (generated image).' : 'Not available.'
  },
  binary: binaries
}];

const prepared = $items('Prepare Binary Upload Payload', 0, 0)?.[0]?.json || {};
const imageUrn = String(prepared.imageUrn || '').trim();
if (!imageUrn) throw new Error('Prepared upload payload is missing image URN.');
return [{ json: { ...prepared, imageUploadStatus: 'uploaded_to_linkedin' } }];

const source = $items('Preview Output', 0, 0)[0].json;
const linkedInPersonUrn = String(source.linkedInPersonUrn || 'ILdXt_7ylP').trim();
const linkedInOrgUrn = String(source.linkedInOrgUrn || '108001978').trim();
const postAsOrg = Boolean(source.postAsOrg ?? true);
const authorUrn = String(source.authorUrn || (postAsOrg ? `urn:li:organization:${linkedInOrgUrn}` : `urn:li:person:${linkedInPersonUrn}`)).trim();
return [{ json: { ...source, linkedInPersonUrn, linkedInOrgUrn, postAsOrg, authorUrn, imageUrn: '', imageUploadStatus: 'skipped_no_image' } }];

const item = $input.first() || {};
const binary = item.binary || {};
const fallbackPersonId = 'ILdXt_7ylP';
const fallbackOrgId = '108001978';
const previewSource = $items('Preview Output', 0, 0)?.[0]?.json || {};
const currentJson = item.json || {};
const source = Object.keys(previewSource).length ? previewSource : currentJson;
const linkedInPersonUrn = String(source.linkedInPersonUrn || currentJson.linkedInPersonUrn || fallbackPersonId).trim();
const linkedInOrgUrn = String(source.linkedInOrgUrn || currentJson.linkedInOrgUrn || fallbackOrgId).trim();
